     1|/**
     2| * Instagram-style property video card — Android/Expo mirror of the iOS
     3| * `DealVideoCard.swift` and the landing-page home feed card.
     4| *
     5| * Header row with IVX avatar, autoplaying muted looping video, action rail
     6| * (like / comment / share / save), real engagement counts, caption, deal chips
     7| * with a gold "View Deal" / "Invest Now" CTA.
     8| */
     9|import React, { useState, useCallback } from 'react';
    10|import { View, Text, StyleSheet, TouchableOpacity, Share, Alert } from 'react-native';
    11|import { Video, ResizeMode } from 'expo-av';
    12|import { useRouter } from 'expo-router';
    13|import {
    14|  Heart,
    15|  MessageCircle,
    16|  Send,
    17|  Bookmark,
    18|  Volume2,
    19|  VolumeX,
    20|  MoreHorizontal,
    21|  Hexagon,
    22|  Users,
    23|  Home,
    24|} from 'lucide-react-native';
    25|import * as Haptics from 'expo-haptics';
    26|import Colors from '@/constants/colors';
    27|import { toggleProjectLike, trackProjectShare } from '@/lib/project-engagement';
    28|import { toggleVideoSave, reportVideo, getViewerId, buildVideoShareUrl } from '@/lib/video-platform';
    29|import type { FeedVideo } from '@/lib/video-feed';
    30|
    31|const MEDIA_HEIGHT = 230;
    32|
    33|function compactCurrency(value: number): string {
    34|  if (value >= 1_000_000) {
    35|    const millions = value / 1_000_000;
    36|    return `$${millions % 1 === 0 ? millions.toFixed(0) : millions.toFixed(1)}M`;
    37|  }
    38|  if (value >= 1_000) {
    39|    const thousands = value / 1_000;
    40|    return `$${thousands % 1 === 0 ? thousands.toFixed(0) : thousands.toFixed(1)}K`;
    41|  }
    42|  return `$${Math.round(value)}`;
    43|}
    44|
    45|function formatCount(n: number): string {
    46|  if (n >= 1000000) return `${(n / 1000000).toFixed(1)}M`;
    47|  if (n >= 1000) return `${(n / 1000).toFixed(1)}K`;
    48|  return String(n);
    49|}
    50|
    51|function Chip({ label, value, tint }: { label: string; value: string; tint: string }) {
    52|  return (
    53|    <View style={styles.chip}>
    54|      <Text style={styles.chipLabel}>{label}</Text>
    55|      <Text style={[styles.chipValue, { color: tint }]}>{value}</Text>
    56|    </View>
    57|  );
    58|}
    59|
    60|type InvestmentOption = { id: string; label: string; icon: React.ReactNode; tint: string };
    61|
    62|function useInvestmentOptions(dealType: string | null | undefined): InvestmentOption[] {
    63|  const t = (dealType ?? '').toLowerCase();
    64|  const tokenized: InvestmentOption = { id: 'tokenized', label: 'Tokenized', icon: <Hexagon size={16} color={Colors.primary} />, tint: Colors.primary };
    65|  const jvDeals: InvestmentOption = { id: 'jvDeals', label: 'JV Deal', icon: <Users size={16} color={Colors.blue} />, tint: Colors.blue };
    66|  const buyers: InvestmentOption = { id: 'buyers', label: 'Buyer', icon: <Home size={16} color={Colors.green} />, tint: Colors.green };
    67|  switch (t) {
    68|    case 'jv':
    69|    case 'equity_split':
    70|    case 'hybrid':
    71|      return [tokenized, jvDeals, buyers];
    72|    case 'development':
    73|    case 'new_construction':
    74|    case 'rehab_construction':
    75|      return [jvDeals, tokenized, buyers];
    76|    case 'profit_sharing':
    77|      return [tokenized, buyers, jvDeals];
    78|    default:
    79|      return [jvDeals, tokenized, buyers];
    80|  }
    81|}
    82|
    83|function OptionIcon({ option }: { option: InvestmentOption }) {
    84|  return (
    85|    <View style={styles.optionIcon}>
    86|      <View style={[styles.optionIconCircle, { borderColor: option.tint + '66' }]}>
    87|        {option.icon}
    88|      </View>
    89|      <Text style={styles.optionIconLabel}>{option.label}</Text>
    90|    </View>
    91|  );
    92|}
