    94|export default function DealVideoCard({ video }: { video: FeedVideo }) {
    95|  const router = useRouter();
    96|  const [isMuted, setIsMuted] = useState<boolean>(true);
    97|  const [liked, setLiked] = useState<boolean>(false);
    98|  const [likeCount, setLikeCount] = useState<number>(video.like_count ?? 0);
    99|  const [saved, setSaved] = useState<boolean>(false);
   100|  const [saveCount, setSaveCount] = useState<number>(video.save_count ?? 0);
   101|  const [viewerId, setViewerId] = useState<string | null>(null);
   102|
   103|  React.useEffect(() => {
   104|    void getViewerId().then(setViewerId);
   105|  }, []);
   106|
   107|  const deal = video.deal ?? null;
   108|  const playbackUri = video.hls_url ?? video.video_url;
   109|  const posterUri = video.poster_url ?? video.thumbnail_url ?? video.preview_blur_url ?? undefined;
   110|  const investmentOptions = useInvestmentOptions(deal?.deal_type);
   111|
   112|  const toggleMute = useCallback(() => setIsMuted(prev => !prev), []);
   113|
   114|  const handleLike = useCallback(async () => {
   115|    void Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
   116|    const nextLiked = !liked;
   117|    setLiked(nextLiked);
   118|    setLikeCount(prev => prev + (nextLiked ? 1 : -1));
   119|    try {
   120|      const result = await toggleProjectLike(video.id, null);
   121|      setLiked(result.liked);
   122|      setLikeCount(result.likeCount);
   123|    } catch {
   124|      setLiked(liked);
   125|      setLikeCount(video.like_count ?? 0);
   126|    }
   127|  }, [liked, video.id, video.like_count]);
   128|
   129|  const handleSave = useCallback(async () => {
   130|    void Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
   131|    const nextSaved = !saved;
   132|    setSaved(nextSaved);
   133|    setSaveCount(prev => prev + (nextSaved ? 1 : -1));
   134|    try {
   135|      const result = await toggleVideoSave(video.id, viewerId);
   136|      setSaved(result.saved);
   137|      setSaveCount(result.saveCount);
   138|    } catch {
   139|      setSaved(saved);
   140|      setSaveCount(video.save_count ?? 0);
   141|    }
   142|  }, [saved, video.id, video.save_count, viewerId]);
   143|
   144|  const handleComment = useCallback(() => {
   145|    router.push({ pathname: '/videos', params: { type: 'reel', focus: video.id } } as any);
   146|  }, [router, video.id]);
   147|
   148|  const handleShare = useCallback(async () => {
   149|    const url = buildVideoShareUrl(video.id);
   150|    const message = `${video.title ?? 'IVX Property'} — ${url}`;
   151|    try {
   152|      await Share.share({ message });
   153|      void trackProjectShare(video.id, 'social', null);
   154|    } catch {}
   155|  }, [video.id, video.title]);
   156|
   157|  const handleReport = useCallback(() => {
   158|    Alert.prompt('Report this video', 'Reason:', async (reason) => {
   159|      if (!reason) return;
   160|      const result = await reportVideo(video.id, reason, viewerId);
   161|      Alert.alert(result.ok ? 'Report submitted' : 'Report failed');
   162|    });
   163|  }, [video.id, viewerId]);
   164|
   165|  const handleViewDeal = useCallback(() => {
   166|    if (deal?.id) {
   167|      router.push({ pathname: '/jv-invest', params: { jvId: deal.id } } as any);
   168|    }
   169|  }, [deal, router]);
   170|
   171|  const handleInvestNow = useCallback(() => {
   172|    if (deal?.id) {
   173|      router.push({ pathname: '/jv-invest', params: { jvId: deal.id } } as any);
   174|    }
   175|  }, [deal, router]);
   176|
   177|  return (
   178|    <View style={styles.card} testID={`deal-video-card-${video.id}`}>
   179|      {/* Header */}
   180|      <View style={styles.header}>
   181|        <View style={styles.avatar}>
   182|          <Text style={styles.avatarText}>IVX</Text>
   183|        </View>
   184|        <View style={styles.headerText}>
   185|          <Text style={styles.accountName}>ivxholdings</Text>
   186|          <Text style={styles.propertyName} numberOfLines={1}>
   187|            {deal?.title ?? video.title ?? 'IVX Holdings'}
   188|          </Text>
   189|        </View>
   190|        <TouchableOpacity onPress={handleReport} hitSlop={{ top: 10, bottom: 10, left: 10, right: 10 }}>
   191|          <MoreHorizontal size={18} color={Colors.textSecondary} />
   192|        </TouchableOpacity>
   193|      </View>
   194|
   195|      {/* Media */}
   196|      <TouchableOpacity activeOpacity={1} onPress={toggleMute} style={styles.media}>
   197|        <Video
   198|          source={{ uri: playbackUri }}
   199|          style={StyleSheet.absoluteFill}
   200|          resizeMode={ResizeMode.COVER}
   201|          shouldPlay
   202|          isLooping
   203|          isMuted={isMuted}
   204|          posterSource={posterUri ? { uri: posterUri } : undefined}
   205|          usePoster={!!posterUri}
   206|        />
   207|        <TouchableOpacity style={styles.muteBtn} onPress={toggleMute} testID={`deal-video-mute-${video.id}`}>
   208|          {isMuted ? <VolumeX size={14} color="#fff" /> : <Volume2 size={14} color="#fff" />}
   209|        </TouchableOpacity>
   210|      </TouchableOpacity>
   211|
   212|      {/* Action rail */}
   213|      <View style={styles.actionRail}>
   214|        <TouchableOpacity onPress={handleLike} testID={`deal-video-like-${video.id}`}>
   215|          <Heart
   216|            size={24}
   217|            color={liked ? Colors.error : '#fff'}
   218|            fill={liked ? Colors.error : 'transparent'}
   219|          />
   220|        </TouchableOpacity>
   221|        <TouchableOpacity onPress={handleComment} testID={`deal-video-comment-${video.id}`}>
   222|          <MessageCircle size={24} color="#fff" />
   223|        </TouchableOpacity>
   224|        <TouchableOpacity onPress={handleShare} testID={`deal-video-share-${video.id}`}>
   225|          <Send size={24} color="#fff" />
   226|        </TouchableOpacity>
   227|        <View style={styles.railSpacer} />
   228|        <TouchableOpacity onPress={handleSave} testID={`deal-video-save-${video.id}`}>
   229|          <Bookmark
   230|            size={24}
   231|            color={saved ? Colors.primary : '#fff'}
   232|            fill={saved ? Colors.primary : 'transparent'}
   233|          />
   234|        </TouchableOpacity>
   235|      </View>
   236|
   237|      {/* Likes line */}
   238|      <Text style={styles.likesLine}>
   239|        {formatCount(likeCount)} like{likeCount === 1 ? '' : 's'}
   240|      </Text>
   241|
   242|      {/* Caption */}
   243|      <Text style={styles.caption} numberOfLines={2}>
   244|        <Text style={styles.captionBold}>ivxholdings </Text>
   245|        {video.title ?? 'Property tour'}
   246|      </Text>
   247|
   248|      {/* Deal chips + CTAs */}
   249|      {deal ? (
   250|        <View style={styles.dealSection}>
   251|          <View style={styles.chipsRow}>
   252|            {deal.expected_roi ? <Chip label="ROI" value={`${deal.expected_roi}%`} tint={Colors.green} /> : null}
   253|            {deal.price && deal.price > 0 ? <Chip label="Value" value={compactCurrency(deal.price)} tint={Colors.primary} /> : null}
   254|            {deal.min_investment && deal.min_investment > 0 ? (
   255|              <Chip label="Min" value={compactCurrency(deal.min_investment)} tint={Colors.text} />
   256|            ) : null}
   257|          </View>
   258|          <View style={styles.optionsRow}>
   259|            {investmentOptions.map((option) => (
   260|              <OptionIcon key={option.id} option={option} />
   261|            ))}
   262|          </View>
   263|          <View style={styles.ctaRow}>
   264|            <TouchableOpacity
   265|              style={styles.viewDealBtn}
   266|              onPress={handleViewDeal}
   267|              activeOpacity={0.85}
   268|              testID={`deal-video-view-${video.id}`}
   269|            >
   270|              <Text style={styles.viewDealText}>View Deal</Text>
   271|            </TouchableOpacity>
   272|            <TouchableOpacity
   273|              style={styles.investNowBtn}
   274|              onPress={handleInvestNow}
   275|              activeOpacity={0.85}
   276|              testID={`deal-video-invest-${video.id}`}
   277|            >
   278|              <Text style={styles.investNowText}>Invest Now</Text>
   279|            </TouchableOpacity>
   280|          </View>
   281|        </View>
   282|      ) : (
   283|        <View style={{ height: 12 }} />
   284|      )}
   285|    </View>
   286|  );
   287|}
